    /// Generate a mnemonic phrase (simplified BIP39)
    func generateMnemonic(wordCount: Int = 12) -> String {
        var words: [String] = []
        for _ in 0..<wordCount {
            let randomBytes = SymmetricKey(size: .bits256)
            let data = randomBytes.withUnsafeBytes { Data($0) }
            let index = Int(data[0]) % wordList.count
            words.append(wordList[index])
        }
        return words.joined(separator: " ")
    }
    
    /// Derive a private key from mnemonic (simplified - production should use proper BIP32/39/44)
    func deriveKeyFromMnemonic(_ mnemonic: String) -> P256.Signing.PrivateKey {
        let mnemonicData = Data(mnemonic.utf8)
        let salt = Data("mnemonic".utf8)
        
        // PBKDF2-like derivation using HKDF
        let inputKey = SymmetricKey(data: mnemonicData)
        let derivedKey = HKDF<SHA256>.deriveKey(
            inputKeyMaterial: inputKey,
            salt: salt,
            info: Data("secp256k1-key".utf8),
            outputByteCount: 32
        )
        
        let keyData = derivedKey.withUnsafeBytes { Data($0) }
        
        // Use the derived bytes to create a deterministic key
        if let key = try? P256.Signing.PrivateKey(rawRepresentation: keyData) {
            return key
        }
        
        // Fallback: generate a new random key
        return P256.Signing.PrivateKey()
    }
    
    /// Generate a new key pair
    func generateKeyPair() -> P256.Signing.PrivateKey {
        return P256.Signing.PrivateKey()
    }
    
    /// Derive an Ethereum-style address from public key
    func deriveAddress(from publicKey: P256.Signing.PublicKey) -> String {
        let publicKeyData = publicKey.rawRepresentation
        let hash = SHA256.hash(data: publicKeyData)
        let addressBytes = Array(hash.suffix(20))
        let address = "0x" + addressBytes.map { String(format: "%02x", $0) }.joined()
        return address
    }
    
    /// Sign data with private key
    func sign(data: Data, with privateKey: P256.Signing.PrivateKey) throws -> P256.Signing.ECDSASignature {
        do {
            let signature = try privateKey.signature(for: data)
            return signature
        } catch {
            throw WalletError.signingFailed
        }
    }
    
    /// Verify signature
    func verify(signature: P256.Signing.ECDSASignature, for data: Data, publicKey: P256.Signing.PublicKey) -> Bool {
        return publicKey.isValidSignature(signature, for: data)
    }
    
    /// Hash transaction data
    func hashTransaction(_ transaction: Transaction) -> Data {
        let encoder = JSONEncoder()
        encoder.outputFormatting = .sortedKeys
        guard let data = try? encoder.encode(transaction) else {
            return Data(SHA256.hash(data: Data("\(transaction.hash)".utf8)))
        }
        return Data(SHA256.hash(data: data))
    }
