final class WalletManager: ObservableObject {
    static let shared = WalletManager()
    
    @Published private(set) var wallets: [Wallet] = []
    @Published private(set) var activeWallet: Wallet?
    @Published private(set) var balance: Decimal = 0
    
    private let keychainManager = KeychainManager.shared
    private let cryptoEngine = CryptoEngine.shared
    private let walletsKey = "stored_wallets"
    
    private init() {
        loadWallets()
    }
    
    // MARK: - Wallet Creation
    
    /// Create a new wallet with a generated mnemonic
    func createWallet() throws -> (wallet: Wallet, mnemonic: String) {
        let mnemonic = cryptoEngine.generateMnemonic()
        let privateKey = cryptoEngine.deriveKeyFromMnemonic(mnemonic)
        let publicKey = privateKey.publicKey
        let address = cryptoEngine.deriveAddress(from: publicKey)
        
        // Store private key in Keychain
        try keychainManager.storePrivateKey(privateKey.rawRepresentation, forAddress: address)
        
        let wallet = Wallet(
            address: address,
            publicKeyHex: publicKey.rawRepresentation.map { String(format: "%02x", $0) }.joined(),
            createdAt: Date()
        )
        
        wallets.append(wallet)
        if activeWallet == nil {
            activeWallet = wallet
        }
        saveWallets()
        
        return (wallet, mnemonic)
    }
    
    /// Import wallet from mnemonic
    func importWallet(mnemonic: String) throws -> Wallet {
        let words = mnemonic.split(separator: " ").map(String.init)
        guard words.count == 12 || words.count == 24 else {
            throw WalletError.invalidMnemonic
        }
        
        let privateKey = cryptoEngine.deriveKeyFromMnemonic(mnemonic)
        let publicKey = privateKey.publicKey
        let address = cryptoEngine.deriveAddress(from: publicKey)
        
        // Check if wallet already exists
        if wallets.contains(where: { $0.address == address }) {
            throw WalletError.invalidAddress
        }
        
        try keychainManager.storePrivateKey(privateKey.rawRepresentation, forAddress: address)
        
        let wallet = Wallet(
            address: address,
            publicKeyHex: publicKey.rawRepresentation.map { String(format: "%02x", $0) }.joined(),
            createdAt: Date()
        )
        
        wallets.append(wallet)
        if activeWallet == nil {
            activeWallet = wallet
        }
        saveWallets()
        
        return wallet
    }
    
    /// Import wallet from private key hex
    func importWallet(privateKeyHex: String) throws -> Wallet {
        guard let keyData = Data(hexString: privateKeyHex) else {
            throw WalletError.keyGenerationFailed
        }
        
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: keyData)
        let publicKey = privateKey.publicKey
        let address = cryptoEngine.deriveAddress(from: publicKey)
        
        try keychainManager.storePrivateKey(privateKey.rawRepresentation, forAddress: address)
        
        let wallet = Wallet(
            address: address,
            publicKeyHex: publicKey.rawRepresentation.map { String(format: "%02x", $0) }.joined(),
            createdAt: Date()
        )
        
        wallets.append(wallet)
        if activeWallet == nil {
            activeWallet = wallet
        }
        saveWallets()
        
        return wallet
    }
    
    // MARK: - Transaction Signing
    
    func signTransaction(_ transaction: Transaction) throws -> SignedTransaction {
        guard let wallet = activeWallet else {
            throw WalletError.keyNotFound
        }
        
        guard transaction.from.lowercased() == wallet.address.lowercased() else {
            throw WalletError.invalidAddress
        }
        
        let privateKeyData = try keychainManager.retrievePrivateKey(forAddress: wallet.address)
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        
        let transactionHash = cryptoEngine.hashTransaction(transaction)
        let signature = try cryptoEngine.sign(data: transactionHash, with: privateKey)
        
        let sigData = signature.rawRepresentation
        let r = sigData.prefix(32).map { String(format: "%02x", $0) }.joined()
        let s = sigData.suffix(32).map { String(format: "%02x", $0) }.joined()
        let v = transaction.chainId * 2 + 35
        
        return SignedTransaction(
            transaction: transaction,
            signature: sigData.map { String(format: "%02x", $0) }.joined(),
            v: v,
            r: r,
            s: s
        )
    }
    
    /// Sign arbitrary message
    func signMessage(_ message: String) throws -> String {
        guard let wallet = activeWallet else {
            throw WalletError.keyNotFound
        }
        
        let prefix = "\u{19}Ethereum Signed Message:\n\(message.count)"
        let prefixedMessage = prefix + message
        let messageHash = Data(SHA256.hash(data: Data(prefixedMessage.utf8)))
        
        let privateKeyData = try keychainManager.retrievePrivateKey(forAddress: wallet.address)
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let signature = try cryptoEngine.sign(data: messageHash, with: privateKey)
        
        return signature.rawRepresentation.map { String(format: "%02x", $0) }.joined()
    }
    
    // MARK: - Wallet Management
    
    func setActiveWallet(_ wallet: Wallet) {
        activeWallet = wallet
    }
    
    func deleteWallet(_ wallet: Wallet) throws {
        try keychainManager.deletePrivateKey(forAddress: wallet.address)
        wallets.removeAll { $0.address == wallet.address }
        
        if activeWallet?.address == wallet.address {
            activeWallet = wallets.first
        }
        saveWallets()
    }
    
    func exportPrivateKey(forAddress address: String) throws -> String {
        let keyData = try keychainManager.retrievePrivateKey(forAddress: address)
        return keyData.map { String(format: "%02x", $0) }.joined()
    }
    
    // MARK: - Persistence
    
    private func saveWallets() {
        if let data = try? JSONEncoder().encode(wallets) {
            UserDefaults.standard.set(data, forKey: walletsKey)
        }
    }
    
    private func loadWallets() {
        guard let data = UserDefaults.standard.data(forKey: walletsKey),
              let stored = try? JSONDecoder().decode([Wallet].self, from: data) else {
            return
        }
        wallets = stored
        activeWallet = wallets.first
    }
}

