struct JSONRPCRequest: Codable {
    let jsonrpc: String
    let method: String
    let params: [JSONRPCParam]
    let id: Int
}

enum JSONRPCParam: Codable {
    case string(String)
    case dict([String: String])
    case array([String])
    
    func encode(to encoder: Encoder) throws {
        var container = encoder.singleValueContainer()
        switch self {
        case .string(let value):
            try container.encode(value)
        case .dict(let value):
            try container.encode(value)
        case .array(let value):
            try container.encode(value)
        }
    }
    
    init(from decoder: Decoder) throws {
        let container = try decoder.singleValueContainer()
        if let string = try? container.decode(String.self) {
            self = .string(string)
        } else if let dict = try? container.decode([String: String].self) {
            self = .dict(dict)
        } else if let array = try? container.decode([String].self) {
            self = .array(array)
        } else {
            self = .string("")
        }
    }
}

struct JSONRPCResponse: Codable {
    let jsonrpc: String
    let id: Int
    let result: String?
    let error: JSONRPCError?
}

struct JSONRPCError: Codable {
    let code: Int
    let message: String
}

final class BlockchainService {
    static let shared = BlockchainService()
    
    private var apiKey: String = "YOUR_INFURA_API_KEY" // Replace with actual key
    private var currentNetwork: BlockchainNetwork = .ethereumSepolia
    private let session: URLSession
    
    private init() {
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        session = URLSession(configuration: config)
    }
    
    func setNetwork(_ network: BlockchainNetwork) {
        currentNetwork = network
    }
    
    func setAPIKey(_ key: String) {
        apiKey = key
    }
    
    private func rpcURL() -> URL {
        var urlString = currentNetwork.rawValue
        if urlString.contains("infura") {
            urlString += apiKey
        }
        return URL(string: urlString)!
    }
    
    // MARK: - RPC Methods
    
    private func makeRPCCall(method: String, params: [JSONRPCParam]) async throws -> String {
        let request = JSONRPCRequest(
            jsonrpc: "2.0",
            method: method,
            params: params,
            id: 1
        )
        
        var urlRequest = URLRequest(url: rpcURL())
        urlRequest.httpMethod = "POST"
        urlRequest.setValue("application/json", forHTTPHeaderField: "Content-Type")
        urlRequest.httpBody = try JSONEncoder().encode(request)
        
        let (data, response) = try await session.data(for: urlRequest)
        
        guard let httpResponse = response as? HTTPURLResponse,
              200...299 ~= httpResponse.statusCode else {
            throw WalletError.networkError("HTTP error")
        }
        
        let rpcResponse = try JSONDecoder().decode(JSONRPCResponse.self, from: data)
        
        if let error = rpcResponse.error {
            throw WalletError.networkError(error.message)
        }
        
        guard let result = rpcResponse.result else {
            throw WalletError.networkError("Empty response")
        }
        
        return result
    }
    
    /// Get balance for an address
    func getBalance(address: String) async throws -> Decimal {
        let result = try await makeRPCCall(
            method: "eth_getBalance",
            params: [.string(address), .string("latest")]
        )
        
        // Parse hex balance
        let hexBalance = result.hasPrefix("0x") ? String(result.dropFirst(2)) : result
        guard let balanceWei = UInt64(hexBalance, radix: 16) else {
            return 0
        }
        
        // Convert from Wei to ETH (or native token)
        let balance = Decimal(balanceWei) / Decimal(1_000_000_000_000_000_000)
        return balance
    }
    
    /// Get transaction count (nonce) for address
    func getTransactionCount(address: String) async throws -> Int {
        let result = try await makeRPCCall(
            method: "eth_getTransactionCount",
            params: [.string(address), .string("latest")]
        )
        
        let hexCount = result.hasPrefix("0x") ? String(result.dropFirst(2)) : result
        return Int(hexCount, radix: 16) ?? 0
    }
    
    /// Get current gas price
    func getGasPrice() async throws -> Decimal {
        let result = try await makeRPCCall(
            method: "eth_gasPrice",
            params: []
        )
        
        let hexPrice = result.hasPrefix("0x") ? String(result.dropFirst(2)) : result
        guard let gasPriceWei = UInt64(hexPrice, radix: 16) else {
            return 0
        }
        
        return Decimal(gasPriceWei)
    }
    
    /// Get current block number
    func getBlockNumber() async throws -> Int {
        let result = try await makeRPCCall(
            method: "eth_blockNumber",
            params: []
        )
        
        let hexBlock = result.hasPrefix("0x") ? String(result.dropFirst(2)) : result
        return Int(hexBlock, radix: 16) ?? 0
    }
    
    /// Send signed transaction
    func sendTransaction(_ signedTx: SignedTransaction) async throws -> String {
        // Encode the signed transaction as RLP-encoded hex
        let txHex = encodeSignedTransaction(signedTx)
        
        let result = try await makeRPCCall(
            method: "eth_sendRawTransaction",
            params: [.string(txHex)]
        )
        
        return result
    }
    
    /// Get transaction receipt
    func getTransactionReceipt(txHash: String) async throws -> TransactionReceipt {
        let result = try await makeRPCCall(
            method: "eth_getTransactionReceipt",
            params: [.string(txHash)]
        )
        
        // Simplified parsing
        return TransactionReceipt(
            transactionHash: txHash,
            status: result.contains("0x1"),
            blockNumber: nil,
            gasUsed: nil
        )
    }
    
    /// Estimate gas for transaction
    func estimateGas(from: String, to: String, value: Decimal) async throws -> Int {
        let valueWei = value * Decimal(1_000_000_000_000_000_000)
        let valueHex = "0x" + String(NSDecimalNumber(decimal: valueWei).uint64Value, radix: 16)
        
        let result = try await makeRPCCall(
            method: "eth_estimateGas",
            params: [.dict([
                "from": from,
                "to": to,
                "value": valueHex
            ])]
        )
        
        let hexGas = result.hasPrefix("0x") ? String(result.dropFirst(2)) : result
        return Int(hexGas, radix: 16) ?? 21000
    }
    
    // MARK: - Transaction Encoding
    
    private func encodeSignedTransaction(_ signedTx: SignedTransaction) -> String {
        // Simplified RLP encoding for the transaction
        let tx = signedTx.transaction
        var components: [String] = []
        
        components.append(encodeHex(tx.nonce))
        components.append(encodeDecimalToHex(tx.gasPrice))
        components.append(encodeHex(tx.gasLimit))
        components.append(tx.to)
        components.append(encodeDecimalToHex(tx.amount * Decimal(1_000_000_000_000_000_000)))
        components.append("0x") // data (empty for simple transfer)
        components.append(encodeHex(signedTx.v))
        components.append("0x" + signedTx.r)
        components.append("0x" + signedTx.s)
        
        // In production, this should be proper RLP encoding
        let combined = components.joined()
        return "0x" + Data(combined.utf8).map { String(format: "%02x", $0) }.joined()
    }
    
    private func encodeHex(_ value: Int) -> String {
        return "0x" + String(value, radix: 16)
    }
    
    private func encodeDecimalToHex(_ value: Decimal) -> String {
        let uint64Value = NSDecimalNumber(decimal: value).uint64Value
        return "0x" + String(uint64Value, radix: 16)
    }
}

