            throw WalletError.keyNotFound
        }
        
        guard isValidAddress(to) else {
            throw WalletError.invalidAddress
        }
        
        // Fetch on-chain data
        let nonce = try await blockchainService.getTransactionCount(address: wallet.address)
        let gasPrice = try await blockchainService.getGasPrice()
        let gasLimit = try await blockchainService.estimateGas(from: wallet.address, to: to, value: amount)
        
        // Check balance
        let balance = try await blockchainService.getBalance(address: wallet.address)
        let totalCost = amount + (gasPrice * Decimal(gasLimit) / Decimal(1_000_000_000_000_000_000))
        
        guard balance >= totalCost else {
            throw WalletError.insufficientBalance
        }
        
        return Transaction(
            from: wallet.address,
            to: to,
            amount: amount,
            nonce: nonce,
            gasPrice: gasPrice,
            gasLimit: gasLimit,
            chainId: network.chainId,
            timestamp: Date()
        )
    }
    
    func signAndSend(transaction: Transaction) async throws -> String {
        let signedTx = try walletManager.signTransaction(transaction)
        let txHash = try await blockchainService.sendTransaction(signedTx)
        return txHash
    }
    
    private func isValidAddress(_ address: String) -> Bool {
        let cleanAddress = address.hasPrefix("0x") ? String(address.dropFirst(2)) : address
        return cleanAddress.count == 40 && cleanAddress.allSatisfy { $0.isHexDigit }
    }
}

// MARK: - Transaction History

final class TransactionHistory {
    static let shared = TransactionHistory()
    
    private let storageKey = "transaction_history"
    
    struct HistoryEntry: Codable {
        let txHash: String
        let from: String
        let to: String
        let amount: Decimal
        let network: String
        let timestamp: Date
        let status: TransactionStatus
    }
    
    enum TransactionStatus: String, Codable {
        case pending
        case confirmed
        case failed
    }
    
    private init() {}
    
    func addEntry(_ entry: HistoryEntry) {
        var history = getHistory()
        history.insert(entry, at: 0)
        
        // Keep last 100 transactions
        if history.count > 100 {
            history = Array(history.prefix(100))
        }
        
        if let data = try? JSONEncoder().encode(history) {
            UserDefaults.standard.set(data, forKey: storageKey)
        }
    }
    
    func getHistory() -> [HistoryEntry] {
        guard let data = UserDefaults.standard.data(forKey: storageKey),
              let history = try? JSONDecoder().decode([HistoryEntry].self, from: data) else {
            return []
        }
        return history
    }
    
    func clearHistory() {
        UserDefaults.standard.removeObject(forKey: storageKey)
    }
}

// MARK: - Biometric Authentication

import LocalAuthentication

final class BiometricAuth {
    static let shared = BiometricAuth()
    
    private init() {}
    
    var isBiometricAvailable: Bool {
        let context = LAContext()
        var error: NSError?
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }
    
    var biometricType: String {
        let context = LAContext()
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return "None"
        }
        
        switch context.biometryType {
        case .faceID: return "Face ID"
        case .touchID: return "Touch ID"
        case .opticID: return "Optic ID"
        @unknown default: return "Biometric"
        }
    }
    
    func authenticate(reason: String) async throws -> Bool {
        let context = LAContext()
        context.localizedFallbackTitle = "Use Passcode"
        
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            // Fall back to device passcode
            return try await context.evaluatePolicy(
                .deviceOwnerAuthentication,
                localizedReason: reason
            )
        }
        
        return try await context.evaluatePolicy(
            .deviceOwnerAuthenticationWithBiometrics,
            localizedReason: reason
        )
    }
}

// MARK: - Data Extension

extension Data {
    init?(hexString: String) {
        let hex = hexString.hasPrefix("0x") ? String(hexString.dropFirst(2)) : hexString
        guard hex.count % 2 == 0 else { return nil }
        
        var data = Data()
        var index = hex.startIndex
        while index < hex.endIndex {
            let nextIndex = hex.index(index, offsetBy: 2)
            guard let byte = UInt8(hex[index..<nextIndex], radix: 16) else { return nil }
            data.append(byte)
            index = nextIndex
        }
        self = data
    }
    
    var hexString: String {
        return map { String(format: "%02x", $0) }.joined()
    }
}

