            self?.createNewWallet()
        })
        
        alert.addAction(UIAlertAction(title: "Import from Mnemonic", style: .default) { [weak self] _ in
            self?.showImportMnemonic()
        })
        
        alert.addAction(UIAlertAction(title: "Import from Private Key", style: .default) { [weak self] _ in
            self?.showImportPrivateKey()
        })
        
