            title: "Welcome to Crypto Wallet",
            message: "Create a new wallet or import an existing one to get started.",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Create New Wallet", style: .default) { [weak self] _ in
