        })
        
        alert.addAction(UIAlertAction(title: "Import Wallet", style: .default) { [weak self] _ in
            self?.showImportMnemonic()
        })
        
        present(alert, animated: true)
    }
    
    private func createNewWallet() {
        do {
            let result = try walletManager.createWallet()
            
            let alert = UIAlertController(
                title: "Wallet Created! 🎉",
                message: "IMPORTANT: Write down your recovery phrase and store it safely. This is the ONLY way to recover your wallet.\n\n\(result.mnemonic)\n\nAddress: \(result.wallet.address)",
                preferredStyle: .alert
            )
            
            alert.addAction(UIAlertAction(title: "Copy Mnemonic", style: .default) { _ in
                UIPasteboard.general.string = result.mnemonic
            })
            
            alert.addAction(UIAlertAction(title: "I've Saved It", style: .default) { [weak self] _ in
                self?.refreshBalance()
            })
            
            present(alert, animated: true)
        } catch {
            showError(error)
        }
    }
    
    private func showImportMnemonic() {
        let alert = UIAlertController(title: "Import Wallet", message: "Enter your 12 or 24 word recovery phrase", preferredStyle: .alert)
        alert.addTextField { textField in
            textField.placeholder = "word1 word2 word3 ..."
            textField.autocapitalizationType = .none
            textField.autocorrectionType = .no
        }
        
        alert.addAction(UIAlertAction(title: "Import", style: .default) { [weak self] _ in
            guard let mnemonic = alert.textFields?.first?.text, !mnemonic.isEmpty else { return }
            
            do {
                let wallet = try self?.walletManager.importWallet(mnemonic: mnemonic)
                self?.refreshBalance()
                
                let successAlert = UIAlertController(title: "Success", message: "Wallet imported: \(wallet?.address ?? "")", preferredStyle: .alert)
                successAlert.addAction(UIAlertAction(title: "OK", style: .default))
                self?.present(successAlert, animated: true)
            } catch {
                self?.showError(error)
            }
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    private func showImportPrivateKey() {
        let alert = UIAlertController(title: "Import Private Key", message: "Enter your private key (hex format)", preferredStyle: .alert)
        alert.addTextField { textField in
            textField.placeholder = "0x..."
            textField.autocapitalizationType = .none
            textField.autocorrectionType = .no
            textField.isSecureTextEntry = true
        }
        
        alert.addAction(UIAlertAction(title: "Import", style: .default) { [weak self] _ in
            guard let keyHex = alert.textFields?.first?.text, !keyHex.isEmpty else { return }
            
            do {
                let wallet = try self?.walletManager.importWallet(privateKeyHex: keyHex)
                self?.refreshBalance()
                
                let successAlert = UIAlertController(title: "Success", message: "Wallet imported: \(wallet?.address ?? "")", preferredStyle: .alert)
                successAlert.addAction(UIAlertAction(title: "OK", style: .default))
                self?.present(successAlert, animated: true)
            } catch {
                self?.showError(error)
            }
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    private func showError(_ error: Error) {
        let alert = UIAlertController(title: "Error", message: error.localizedDescription, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

// MARK: - Send Transaction View Controller

class SendTransactionViewController: UIViewController {
    
    private let walletManager = WalletManager.shared
    private let transactionBuilder = TransactionBuilder()
    private let biometricAuth = BiometricAuth.shared
    
    private let recipientField = UITextField()
    private let amountField = UITextField()
    private let sendButton = UIButton(type: .system)
    private let activityIndicator = UIActivityIndicatorView(style: .medium)
    private let gasPriceLabel = UILabel()
    private let estimatedFeeLabel = UILabel()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        fetchGasPrice()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Send Transaction"
        
        navigationItem.leftBarButtonItem = UIBarButtonItem(barButtonSystemItem: .cancel, target: self, action: #selector(dismissVC))
        
        let stack = UIStackView()
        stack.axis = .vertical
        stack.spacing = 16
        stack.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(stack)
        
        NSLayoutConstraint.activate([
            stack.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            stack.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            stack.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20)
        ])
        
        // Recipient
        let recipientLabel = UILabel()
        recipientLabel.text = "Recipient Address"
        recipientLabel.font = .systemFont(ofSize: 14, weight: .medium)
        
        recipientField.placeholder = "0x..."
        recipientField.borderStyle = .roundedRect
        recipientField.autocapitalizationType = .none
        recipientField.autocorrectionType = .no
        recipientField.font = .monospacedSystemFont(ofSize: 14, weight: .regular)
        
        // Amount
        let amountLabel = UILabel()
        amountLabel.text = "Amount (ETH)"
        amountLabel.font = .systemFont(ofSize: 14, weight: .medium)
        
        amountField.placeholder = "0.0"
        amountField.borderStyle = .roundedRect
        amountField.keyboardType = .decimalPad
        amountField.font = .systemFont(ofSize: 16)
        
        // Gas info
        gasPriceLabel.text = "Gas Price: Loading..."
        gasPriceLabel.font = .systemFont(ofSize: 12)
        gasPriceLabel.textColor = .secondaryLabel
        
        estimatedFeeLabel.text = "Estimated Fee: --"
        estimatedFeeLabel.font = .systemFont(ofSize: 12)
        estimatedFeeLabel.textColor = .secondaryLabel
        
        // Send button
        var config = UIButton.Configuration.filled()
        config.title = "Sign & Send"
        config.image = UIImage(systemName: "paperplane.fill")
        config.imagePadding = 8
        config.baseBackgroundColor = .systemBlue
        config.cornerStyle = .large
        config.contentInsets = NSDirectionalEdgeInsets(top: 14, leading: 20, bottom: 14, trailing: 20)
        sendButton.configuration = config
        sendButton.addTarget(self, action: #selector(sendTransaction), for: .touchUpInside)
        
        // Scan QR button
        let scanButton = UIButton(type: .system)
        scanButton.setTitle("Scan QR Code", for: .normal)
        scanButton.setImage(UIImage(systemName: "qrcode.viewfinder"), for: .normal)
        scanButton.addTarget(self, action: #selector(scanQR), for: .touchUpInside)
        
        stack.addArrangedSubview(recipientLabel)
        stack.addArrangedSubview(recipientField)
        stack.addArrangedSubview(scanButton)
        stack.addArrangedSubview(amountLabel)
        stack.addArrangedSubview(amountField)
        stack.addArrangedSubview(gasPriceLabel)
        stack.addArrangedSubview(estimatedFeeLabel)
        
        let spacer = UIView()
        spacer.heightAnchor.constraint(equalToConstant: 20).isActive = true
        stack.addArrangedSubview(spacer)
        
        stack.addArrangedSubview(sendButton)
        
        activityIndicator.translatesAutoresizingMaskIntoConstraints = false
        activityIndicator.hidesWhenStopped = true
        view.addSubview(activityIndicator)
        NSLayoutConstraint.activate([
            activityIndicator.centerXAnchor.constraint(equalTo: sendButton.centerXAnchor),
            activityIndicator.centerYAnchor.constraint(equalTo: sendButton.centerYAnchor)
        ])
        
        let tapGesture = UITapGestureRecognizer(target: self, action: #selector(dismissKeyboard))
        view.addGestureRecognizer(tapGesture)
    }
    
    private func fetchGasPrice() {
        Task {
            do {
                let gasPrice = try await BlockchainService.shared.getGasPrice()
                let gasPriceGwei = gasPrice / Decimal(1_000_000_000)
                await MainActor.run {
                    self.gasPriceLabel.text = "Gas Price: \(gasPriceGwei) Gwei"
                    let estimatedFee = gasPrice * Decimal(21000) / Decimal(1_000_000_000_000_000_000)
                    self.estimatedFeeLabel.text = "Estimated Fee: \(estimatedFee) ETH"
                }
            } catch {
                await MainActor.run {
                    self.gasPriceLabel.text = "Gas Price: Unable to fetch"
                }
            }
        }
    }
    
    @objc private func sendTransaction() {
        guard let recipient = recipientField.text, !recipient.isEmpty,
              let amountText = amountField.text, let amount = Decimal(string: amountText) else {
            showAlert(title: "Error", message: "Please fill in all fields")
            return
        }
        
        sendButton.isEnabled = false
        activityIndicator.startAnimating()
        
        Task {
            do {
                // Authenticate with biometrics
                if biometricAuth.isBiometricAvailable {
                    let authenticated = try await biometricAuth.authenticate(
                        reason: "Authenticate to sign transaction"
                    )
                    guard authenticated else {
                        throw WalletError.biometricAuthFailed
                    }
                }
                
                // Build and sign transaction
                let transaction = try await transactionBuilder.buildTransaction(
                    to: recipient,
                    amount: amount
                )
                
                let txHash = try await transactionBuilder.signAndSend(transaction: transaction)
                
                // Record in history
                TransactionHistory.shared.addEntry(TransactionHistory.HistoryEntry(
                    txHash: txHash,
                    from: transaction.from,
                    to: transaction.to,
                    amount: transaction.amount,
                    network: "Sepolia",
                    timestamp: Date(),
                    status: .pending
                ))
                
                await MainActor.run {
                    self.activityIndicator.stopAnimating()
                    self.sendButton.isEnabled = true
                    self.showAlert(title: "Transaction Sent! 🎉", message: "TX Hash: \(txHash)") { [weak self] in
                        self?.dismiss(animated: true)
                    }
                }
            } catch {
                await MainActor.run {
                    self.activityIndicator.stopAnimating()
                    self.sendButton.isEnabled = true
                    self.showAlert(title: "Error", message: error.localizedDescription)
                }
            }
        }
    }
    
    @objc private func scanQR() {
        showAlert(title: "QR Scanner", message: "QR code scanning would be implemented here using AVCaptureSession")
    }
    
    @objc private func dismissVC() {
        dismiss(animated: true)
    }
    
    @objc private func dismissKeyboard() {
        view.endEditing(true)
    }
    
    private func showAlert(title: String, message: String, completion: (() -> Void)? = nil) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completion?()
        })
        present(alert, animated: true)
    }
}

