    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Settings"
        navigationItem.leftBarButtonItem = UIBarButtonItem(barButtonSystemItem: .done, target: self, action: #selector(dismissVC))
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "cell")
    }
    
    override func numberOfSections(in tableView: UITableView) -> Int {
        return Section.allCases.count
    }
    
    override func tableView(_ tableView: UITableView, titleForHeaderInSection section: Int) -> String? {
        switch Section(rawValue: section)! {
        case .wallets: return "Wallets"
        case .network: return "Network"
        case .security: return "Security"
        case .about: return "About"
        }
    }
    
    override func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        switch Section(rawValue: section)! {
        case .wallets: return max(walletManager.wallets.count, 1)
        case .network: return BlockchainNetwork.allCases.count
        case .security: return 2
        case .about: return 2
        }
    }
    
    override func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "cell", for: indexPath)
        cell.accessoryType = .none
        cell.textLabel?.textColor = .label
        
        switch Section(rawValue: indexPath.section)! {
        case .wallets:
            if walletManager.wallets.isEmpty {
                cell.textLabel?.text = "No wallets"
                cell.textLabel?.textColor = .tertiaryLabel
            } else {
                let wallet = walletManager.wallets[indexPath.row]
                cell.textLabel?.text = wallet.address
                cell.textLabel?.font = .monospacedSystemFont(ofSize: 12, weight: .regular)
                if wallet.address == walletManager.activeWallet?.